#!/bin/bash
# Test RLP-encoded signed claimAsset transactions against the proxy
#
# This script tests the RLP decode path in the proxy using EIP-1559 signed
# transactions that contain claimAsset calldata.
#
# Unlike test-lumia-claims.sh (which sends raw calldata), this tests the
# full transaction decode path: RLP decode -> signer recovery -> calldata extraction.
#
# Usage:
#   ./scripts/test-rlp-claims.sh           # Test all vectors
#   ./scripts/test-rlp-claims.sh 1         # Test only vector 1
#
# Generate new test vectors:
#   cargo run --example gen_signed_tx

set -e

PROXY_URL="${PROXY_URL:-http://localhost:8546}"

# RLP-encoded signed EIP-1559 transactions containing claimAsset calldata
# Signer: 0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266 (test key)
# Bridge Contract: 0x2a3DD3EB832aF982ec71669E178424b10Dca2EDe
# Chain ID: 1
declare -a RLP_TX_DATA=(
    # TX 1: dest=0xA95867B23955F98a3A5774645DB2B603baba4003, amount=1e18, local_root_index=12345
    ""
    # TX 2: dest=0xD9b20Fe633b609B01081aD0428e81f8Dd604F5C5, amount=315e18, local_root_index=233347
    ""
    # TX 3: dest=0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266 (signer), amount=100, local_root_index=100
    ""
)

declare -a RLP_TX_DESC=(
    "local_root_index=12345, amount=1e18"
    "local_root_index=233347, amount=315e18"
    "local_root_index=100, amount=100"
)

# Function to send a single test transaction
send_tx() {
    local idx=$1
    local tx_data="${RLP_TX_DATA[$idx]}"
    local tx_desc="${RLP_TX_DESC[$idx]}"

    echo "========================================"
    echo "RLP TX $((idx + 1)): $tx_desc"
    echo "========================================"
    echo "Sending RLP-encoded signed transaction to $PROXY_URL..."
    echo ""

    # Build JSON-RPC request
    local request=$(cat <<EOF
{
    "jsonrpc": "2.0",
    "method": "eth_sendRawTransaction",
    "params": ["$tx_data"],
    "id": $((idx + 1))
}
EOF
)

    # Send request
    response=$(curl -s -X POST \
        -H "Content-Type: application/json" \
        -d "$request" \
        "$PROXY_URL")

    echo "Response: $response"
    echo ""

    # Check for error
    if echo "$response" | grep -q '"error"'; then
        echo "   RESULT: ERROR"
        return 1
    else
        echo "   RESULT: OK"
        return 0
    fi
}

# Pre-flight check
preflight_check() {
    echo "Pre-flight checks..."
    echo ""

    # Check proxy is responding
    echo "1. Checking proxy connectivity..."
    response=$(curl -s -X POST \
        -H "Content-Type: application/json" \
        -d '{"jsonrpc":"2.0","method":"eth_chainId","params":[],"id":1}' \
        "$PROXY_URL" 2>/dev/null)

    if [ -z "$response" ]; then
        echo "   FAILED: No response from proxy at $PROXY_URL"
        return 1
    fi

    if echo "$response" | grep -q '"error"'; then
        echo "   FAILED: Proxy returned error: $response"
        return 1
    fi
    echo "   OK: Proxy responding"

    echo ""
    echo "All pre-flight checks passed!"
    echo ""
    return 0
}

# Main
echo "RLP-Encoded Signed claimAsset Test"
echo "==================================="
echo "Proxy URL: $PROXY_URL"
echo ""
echo "Test vectors: ${#RLP_TX_DATA[@]} EIP-1559 signed transactions"
echo "  - Signer: 0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266"
echo "  - Bridge: 0x2a3DD3EB832aF982ec71669E178424b10Dca2EDe"
echo "  - Chain ID: 1"
echo ""

# Run pre-flight checks first
if ! preflight_check; then
    echo ""
    echo "Pre-flight checks FAILED. Aborting tests."
    echo "Please ensure the proxy is running and responding."
    exit 1
fi

# Check if specific indices were provided
if [ $# -gt 0 ]; then
    for arg in "$@"; do
        idx=$((arg - 1))
        if [ $idx -ge 0 ] && [ $idx -lt ${#RLP_TX_DATA[@]} ]; then
            send_tx $idx
        else
            echo "Invalid index: $arg (must be 1-${#RLP_TX_DATA[@]})"
        fi
    done
else
    # Run all test vectors
    for i in $(seq 0 $((${#RLP_TX_DATA[@]} - 1))); do
        send_tx $i
    done
fi

echo "========================================"
echo "Done. Check proxy logs for decode output."
echo ""
echo "The proxy should show:"
echo "  - RLP decode succeeded"
echo "  - Signer recovered: 0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266"
echo "  - claimAsset parameters parsed"
